const body = $input.first().json.body;

  // VA list items (plain strings — assembled into HTML inside this node)
  const vaItems = (body.vas || [])
    .map(va => `<li><strong>${va.name}</strong> — ${va.role}</li>`)
    .join('');

  // Preferred interview date
  let ciDate = 'Not specified';
  const raw = body.form?.preferredStartDate;
  if (raw && raw.includes('T')) {
    const [datePart, timePart] = raw.split('T');
    const [year, month, day] = datePart.split('-').map(Number);
    const [hour, min] = timePart.split(':').map(Number);
    const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const h = hour % 12 || 12;
    const m = String(min).padStart(2, '0');
    ciDate = `${months[month-1]} ${day}, ${year} · ${h}:${m} ${ampm} CT`;
  }

  // Submission timestamp
  let submittedDate = body.submittedAt;
  try {
    submittedDate = new Date(body.submittedAt).toLocaleString('en-US', {
      timeZone: 'America/Chicago',
      month: 'short', day: 'numeric', year: 'numeric',
      hour: 'numeric', minute: '2-digit',
    }) + ' CT';
  } catch(e) {}

  // Airtable interface links (point to interface views, not raw records)
  const baseId         = 'apptuAm73VyH7pcHA';
  const batchPageId    = 'pagqgq7JK3HNWfi09';
  const batchParam     = 'CXUiX';
