    </div>
    <div style="background:#fff;border:1px solid #e5e7eb;border-top:none;padding:24px;border-radius:0 0 8px 8px;">
      <p>Hi ${clientFirstName},</p>
      <p>We've received your interview request and the Placements team is on it. Here's a summary of what was submitted:</p>
      <h3 style="color:#f07d19;margin-bottom:8px;">Your Selected Candidates (${vaCount})</h3>
      <ul style="padding-left:20px;">${vaItems}</ul>
      <h3 style="color:#f07d19;margin-bottom:8px;">Request Details</h3>
      <table style="width:100%;border-collapse:collapse;">
        <tr><td style="padding:8px 0;color:#6b7280;width:160px;">Timeline</td><td style="padding:8px 0;"><strong>${timelineLabel}</strong></td></tr>
        <tr><td style="padding:8px 0;color:#6b7280;">Preferred Interview Date</td><td style="padding:8px 0;"><strong>${ciDate}</strong></td></tr>
        ${notesRowHTML}
      </table>
      <div style="background:#f9fafb;border-radius:6px;padding:16px;margin-top:24px;">
        <h4 style="margin:0 0 8px 0;">What happens next</h4>
        <ol style="margin:0;padding-left:20px;color:#374151;line-height:1.8;">
          <li>The Placements team reviews your selections</li>
          <li>They'll coordinate interview slots with your chosen VAs</li>
          <li>You'll hear back within 1–2 business days to confirm times</li>
        </ol>
      </div>
      <p style="margin-top:24px;color:#6b7280;font-size:13px;">Questions? Reply to this email or reach out to <a href="mailto:placements@scalevirtually.com" 
style="color:#f07d19;">placements@scalevirtually.com</a>.</p>
    </div>
  </div>`;

  // ── Email 2: Placements internal alert ───────────────────────────────────────
  const placementsEmailBody = `
  <div style="font-family:sans-serif;max-width:600px;margin:0 auto;">
    <div style="background:#1e293b;padding:24px;border-radius:8px 8px 0 0;">
      <h1 style="color:white;margin:0;font-size:20px;">🔔 New VA Marketplace Request</h1>
